import{_ as a,o,c as i,ag as n}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Sobretensiones de voltaje","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-quality/voltage-swells.md","filePath":"es/power-quality/voltage-swells.md"}'),s={name:"es/power-quality/voltage-swells.md"};function l(t,e,r,c,d,p){return o(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="sobretensiones-de-voltaje" tabindex="-1">Sobretensiones de voltaje <a class="header-anchor" href="#sobretensiones-de-voltaje" aria-label="Permalink to &quot;Sobretensiones de voltaje&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Las sobretensiones de voltaje son incrementos de corta duración en la magnitud del voltaje por encima de los niveles normales.</p><p>Típicamente duran desde unos pocos milisegundos hasta unos pocos segundos y son menos comunes que las caídas de voltaje, pero aún pueden causar problemas significativos en sistemas industriales.</p><p>Las sobretensiones de voltaje pueden estresar el aislamiento, dañar el equipo y interrumpir la operación normal.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Comprender las sobretensiones de voltaje es importante para:</p><ul><li>Proteger el equipo de condiciones de sobrevoltaje</li><li>Prevenir daños al aislamiento y componentes electrónicos</li><li>Mantener la operación estable de sistemas industriales</li><li>Reducir fallas inesperadas y tiempo de inactividad</li></ul><p>La gestión de sobretensiones de voltaje ayuda a garantizar la confiabilidad a largo plazo del equipo eléctrico.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Una sobretensión de voltaje ocurre cuando hay una reducción súbita de la carga o una perturbación en el sistema que provoca que el voltaje aumente.</p><p>Las causas comunes incluyen:</p><ul><li>Desconexión súbita de cargas de gran tamaño</li><li>Operaciones de conmutación en la red</li><li>Fallas en sistemas cercanos, especialmente fallas a tierra</li><li>Regulación de voltaje inadecuada</li></ul><p>Cuando la corriente disminuye rápidamente, la caída de voltaje a través de la impedancia del sistema se reduce, provocando que el voltaje en la carga aumente temporalmente.</p><p>El impacto depende de:</p><ul><li>Magnitud del incremento de voltaje</li><li>Duración del evento</li><li>Sensibilidad del equipo conectado</li></ul><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Las consideraciones sobre sobretensiones de voltaje son importantes en:</p><ul><li>Sistemas con cargas de gran tamaño o que cambian rápidamente</li><li>Instalaciones con equipos electrónicos sensibles</li><li>Sistemas de automatización y tableros de control</li><li>Variadores de frecuencia y electrónica de potencia</li><li>Instalaciones con operaciones de conmutación frecuentes</li></ul><p>Son relevantes dondequiera que la estabilidad de voltaje sea crítica.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Magnitud de la sobretensión</strong><br> Niveles de voltaje más altos incrementan el riesgo de daño al equipo</p></li><li><p><strong>Duración</strong><br> Sobretensiones más prolongadas tienen mayor impacto en el aislamiento y los componentes</p></li><li><p><strong>Tolerancia del equipo</strong><br> Algunos dispositivos son más sensibles a condiciones de sobrevoltaje</p></li><li><p><strong>Regulación del sistema</strong><br> Los métodos de control de voltaje influyen en la ocurrencia de sobretensiones</p></li><li><p><strong>Operaciones de conmutación</strong><br> La conmutación frecuente puede introducir fluctuaciones de voltaje</p></li><li><p><strong>Protección y mitigación</strong><br> Pueden requerirse dispositivos de protección contra sobrevoltaje</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>La eliminación súbita de carga es una causa interna común de sobretensiones de voltaje</li><li>El equipo electrónico puede fallar incluso con sobrevoltajes de corta duración</li><li>Una regulación de voltaje adecuada reduce la frecuencia de sobretensiones</li><li>Los dispositivos de protección contra sobretensiones pueden ayudar a limitar los efectos del sobrevoltaje</li><li>El monitoreo es útil para detectar condiciones recurrentes de sobretensión</li></ul>',24)])])}const b=a(s,[["render",l]]);export{m as __pageData,b as default};
